#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <math.h>

// simple trial division without pre‑computed primes (fast enough for N ≤ 1e12)
static uint64_t sigma(uint64_t n) {
    uint64_t original = n;
    uint64_t result = 1;
    for (uint64_t p = 2; p * p <= n; ++p) {
        if (n % p) continue;
        uint64_t term = 1;
        uint64_t power = 1;
        while (n % p == 0) {
            n /= p;
            power *= p;
            term += power;
        }
        result *= term;
    }
    if (n > 1) result *= (1 + n); // remaining prime factor
    return result;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        uint64_t X, A, B; scanf("%llu %llu %llu", &X, &A, &B);
        __uint128_t prod = ( (__uint128_t) X) * B;
        if (prod % A != 0) {
            printf("-1\n");
            continue;
        }
        uint64_t N = (uint64_t)(prod / A);
        if (sigma(N) == X) printf("%llu\n", N);
        else printf("-1\n");
    }
    return 0;
}

