import java.io.*;
import java.util.*;

public class Main {
    private static long sigma(long n) {
        long res = 1;
        for (long p = 2; p * p <= n; ++p) {
            if (n % p != 0) continue;
            long term = 1, power = 1;
            while (n % p == 0) {
                n /= p;
                power *= p;
                term += power;
            }
            res *= term;
        }
        if (n > 1) res *= (1 + n);
        return res;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            st = new StringTokenizer(br.readLine());
            long X = Long.parseLong(st.nextToken());
            long A = Long.parseLong(st.nextToken());
            long B = Long.parseLong(st.nextToken());
            java.math.BigInteger prod = java.math.BigInteger.valueOf(X).multiply(java.math.BigInteger.valueOf(B));
            if (!prod.mod(java.math.BigInteger.valueOf(A)).equals(java.math.BigInteger.ZERO)) {
                out.append(-1).append('\n');
                continue;
            }
            long N = prod.divide(java.math.BigInteger.valueOf(A)).longValue();
            if (sigma(N) == X) out.append(N).append('\n');
            else out.append(-1).append('\n');
        }
        System.out.print(out.toString());
    }
}

