#!/usr/bin/env python3
import sys, math

def sigma(n: int) -> int:
    res = 1
    p = 2
    while p * p <= n:
        if n % p:
            p += 1
            continue
        term = 1
        power = 1
        while n % p == 0:
            n //= p
            power *= p
            term += power
        res *= term
        p += 1
    if n > 1:
        res *= (1 + n)
    return res

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); A = int(next(it)); B = int(next(it))
        prod = X * B
        if prod % A != 0:
            out.append('-1')
            continue
        N = prod // A
        if sigma(N) == X:
            out.append(str(N))
        else:
            out.append('-1')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

